/*MstoreMapper.getMstoreTermsAgreeInfo*/
SELECT STRT_DTTM ,END_DTTM, AGR_YN, CUSTOMER_ID
FROM NMCP_MSTORE_TERM_HIST
WHERE USERID= #{userId}
AND END_DTTM= '99991231235959'

mapper.update:
/*MstoreMapper.updateMstoreTermsAgreeInfo*/
UPDATE NMCP_MSTORE_TERM_HIST
SET
   RVISN_DTTM= SYSDATE
  ,RVISN_ID= #{userId}
  ,END_DTTM= TO_CHAR(SYSDATE - 1/24/60/60, 'YYYYMMDDHH24MISS')
WHERE USERID= #{userId}
AND END_DTTM= '99991231235959'

mapper.insert:
/*MstoreMapper.insertMstoreCanTrg*/

SELECT (TO_CHAR(SYSDATE,'YYYYMMDD') || TRIM(TO_CHAR(SQ_MSTORE_CAN_TRG.NEXTVAL, '0000'))) AS canTrgSeq FROM DUAL

INSERT INTO NMCP_MSTORE_CAN_TRG (
    CAN_TRG_SEQ
   ,CHN_CD
   ,PROC_YN
   ,USERID
) VALUES (
    #{canTrgSeq}
   ,#{chnCd}
   ,#{procYn}
   ,#{userId}
)

mapper.update:
MERGE INTO NMCP_MSTORE_SSO_INFO
USING DUAL
ON (USERID = #{userId})
WHEN MATCHED THEN
    UPDATE SET
        EMPEN= #{memId}
       ,MBR_GRD_CD = #{mbrGrdCd}
       ,LST_COM_ACTV_DATE = #{lstComActvDate}
       ,SYS_LDATE = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
       ,RVISN_ID = #{userId}
       ,RVISN_DTTM = SYSDATE
WHEN NOT MATCHED THEN
    INSERT (
        USERID
       ,EMPEN
       ,MBR_GRD_CD
       ,LST_COM_ACTV_DATE
       ,SYS_LDATE
       ,REGST_ID
       ,REGST_DTTM
       ,RVISN_ID
       ,RVISN_DTTM
    ) VALUES (
        #{userId}
       ,#{memId}
       ,#{mbrGrdCd}
       ,#{lstComActvDate}
       ,TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
       ,#{userId}
       ,SYSDATE
       ,#{userId}
       ,SYSDATE
    )
